const b=$json.body||$json;
const q=(b.question||b.pregunta||b.message||'').trim();
if(!q)return[{json:{ok:false,error:'Debes enviar question, pregunta o message.'}}];
return[{json:{question:q,embed:{model:$env.OLLAMA_EMBED_MODEL||'nomic-embed-text',input:q}}}];

const v = Array.isArray($json.embeddings) ? $json.embeddings[0] : [];
const q = $item(0).$node['Build Embed'].json.question;
return [{ json: { question: q, qdrant: { query: v, limit: 3, with_payload: true } } }];

const rawPts = $json.result?.points || $json.result || [];
const q = $item(0).$node['Build Qdrant'].json.question;
const qLower = q.toLowerCase();
const seen = new Set();
const pts = rawPts.filter((p) => {
  const source = p.payload?.source_url || p.payload?.url || 'sin_fuente';
  if (seen.has(source)) return false;
  seen.add(source);
  return true;
}).slice(0, 2);
const sources = pts.map((p) => p.payload?.source_url || p.payload?.url || 'sin_fuente');
const snippets = pts.map((p, i) => {
  const source = p.payload?.source_url || p.payload?.url || 'sin_fuente';
  const text = String(p.payload?.text || p.payload?.chunk || p.payload?.content || '').replace(/\s+/g, ' ').trim().slice(0, 700);
  return `Fuente ${i + 1}: ${source}. ${text}`;
});
const combined = snippets.join(' ').toLowerCase();
const hits = ['reactivo', 'quimico', 'laboratorio', 'desinfectante', 'subasta', 'infima', 'proforma'].filter((token) => combined.includes(token));
let answer = 'No hay contexto local suficiente para responder con precision. Carga mas documentos del proceso o consulta el OCID/NIC exacto.';
if (snippets.length) {
  if (/participar|conviene|oportunidad|ofertar/.test(qLower)) {
    const stance = hits.length >= 2 ? 'hay senales favorables para revisar participacion' : 'todavia se requiere validacion comercial y tecnica';
    answer = `Respuesta basada en la base local. Con el contexto recuperado, ${stance}. Coincidencias detectadas: ${hits.join(', ') || 'sin coincidencias claras'}. ${snippets.join(' ')}`;
  } else {
    answer = `Respuesta basada en la base local. ${snippets.join(' ')}`;
  }
}
return [{ json: { ok: true, mode: 'rag_rules_fallback', answer, sources } }];

if ($json.answer) {
  return [{ json: { ok: $json.ok ?? true, mode: $json.mode || 'rag_rules_fallback', answer: $json.answer, sources: $json.sources || [] } }];
}
return [{ json: { ok: true, mode: 'ollama', answer: $json.message?.content || $json.response || 'Sin respuesta del modelo', sources: $item(0).$node['Build Chat'].json.sources || [] } }];
